queries.sparql:
PREFIX : <http://ambrosia.example.org/hospitality#>
PREFIX p: <http://ambrosia.example.org/hospitality/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?o0 WHERE {
  {
    ?salads a :Salads .
    ?salads p:name ?name .
    ?salads p:BuffetName ?buffetname_f .
    FILTER(STR(?buffetname_f) = "Hilton")
    BIND(?name AS ?o0)
  }
  UNION
  {
    ?soups a :Soups .
    ?soups p:name ?name .
    ?soups p:BuffetName ?buffetname_f .
    FILTER(STR(?buffetname_f) = "Hilton")
    BIND(?name AS ?o0)
  }
}

